const item = $input.first().json;
const hayConflicto = item.estado_sesion === 'pendiente_confirmacion';
const credenciales = typeof item.credenciales_api === 'string'
  ? JSON.parse(item.credenciales_api || '{}')
  : (item.credenciales_api || {});

return [{
  json: {
    ...item,
    credenciales,
    puede_ejecutar: !hayConflicto
  }
}];

const item = $input.first().json;
const accion = item.accion;
const datos = typeof item.datos_json === 'string' ? JSON.parse(item.datos_json) : (item.datos_json || {});
const creds = item.credenciales || {};
const baseUrl = (item.ecommerce_url || '').replace(/\/$/, '');
const ecomTipo = item.ecommerce_tipo;

if (!creds || Object.keys(creds).length === 0) {
  return [{ json: { ...item, _skip: true, _razon: 'sin_credenciales_ecommerce' } }];
}

let httpUrl, httpMethod, httpBody, authHeaderName, authHeaderValue;

if (ecomTipo === 'woocommerce') {
  const ck = creds.consumer_key || '';
  const cs = creds.consumer_secret || '';
  if (!ck || !cs) return [{ json: { ...item, _skip: true, _razon: 'credenciales_woocommerce_incompletas' } }];
  authHeaderName = 'Authorization';
  authHeaderValue = 'Basic ' + Buffer.from(ck + ':' + cs).toString('base64');
  const apiBase = baseUrl + '/wp-json/wc/v3';
  if (accion === 'actualizar_precio') {
    httpUrl = apiBase + '/products/' + datos.producto_id;
    httpMethod = 'PUT';
    httpBody = JSON.stringify({ regular_price: String(datos.precio) });
  } else if (accion === 'actualizar_producto') {
    httpUrl = apiBase + '/products/' + datos.producto_id;
    httpMethod = 'PUT';
    httpBody = JSON.stringify(datos.campos || {});
  } else if (accion === 'crear_descuento') {
    httpUrl = apiBase + '/products/' + datos.producto_id;
    httpMethod = 'PUT';
    httpBody = JSON.stringify({ sale_price: String(datos.valor || datos.precio_especial || '') });
  } else {
    return [{ json: { ...item, _skip: true, _razon: 'accion_no_soportada_wc: ' + accion } }];
  }
} else if (ecomTipo === 'shopify') {
  const token = creds.access_token || '';
  if (!token) return [{ json: { ...item, _skip: true, _razon: 'credenciales_shopify_incompletas' } }];
  authHeaderName = 'X-Shopify-Access-Token';
  authHeaderValue = token;
  const apiBase = baseUrl + '/admin/api/2024-01';
  if (accion === 'actualizar_precio') {
    const varianteId = datos.variante_id;
    if (!varianteId) return [{ json: { ...item, _skip: true, _razon: 'shopify_requiere_variante_id' } }];
    httpUrl = apiBase + '/variants/' + varianteId + '.json';
    httpMethod = 'PUT';
    httpBody = JSON.stringify({ variant: { id: varianteId, price: String(datos.precio) } });
  } else if (accion === 'actualizar_producto') {
    httpUrl = apiBase + '/products/' + datos.producto_id + '.json';
    httpMethod = 'PUT';
    httpBody = JSON.stringify({ product: datos.campos || {} });
  } else {
    return [{ json: { ...item, _skip: true, _razon: 'accion_no_soportada_shopify: ' + accion } }];
  }
} else {
  return [{ json: { ...item, _skip: true, _razon: 'ecommerce_tipo_desconocido: ' + ecomTipo } }];
}

return [{
  json: {
    ...item,
    _http_url: httpUrl,
    _http_method: httpMethod,
    _http_body: httpBody,
    _auth_header_name: authHeaderName,
    _auth_header_value: authHeaderValue,
    _skip: false
  }
}];

const errorData = $input.first().json;
return [{
  json: {
    workflow: 'WF-E_scheduler',
    nodo: errorData.execution?.lastNodeExecuted || 'desconocido',
    error_tipo: 'ERROR_CRITICO_SCHEDULER',
    error_detalle: errorData.error?.message || JSON.stringify(errorData.error || {})
  }
}];
